import{_ as e,o as d,c as a,ae as r}from"./chunks/framework.B6gjLfeO.js";const _=JSON.parse('{"title":"Postback Macros and Functions","description":"","frontmatter":{"title":"Postback Macros and Functions","slug":"postback-macros-functions"},"headers":[],"relativePath":"developer-hub/postback-macros-functions.md","filePath":"developer-hub/postback-macros-functions.md"}'),o={name:"developer-hub/postback-macros-functions.md"};function i(c,t,s,n,l,h){return d(),a("div",null,[...t[0]||(t[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The following list shows the macros and available functions that Branch supports in your Postback URLs and Webhooks. When you use these macros and functions, Branch dynamically resolves/replaces them with their corresponding values before notifying the specified postback URL.</p><h2 id="url-macros" tabindex="-1">URL Macros <a class="header-anchor" href="#url-macros" aria-label="Permalink to &quot;URL Macros&quot;">​</a></h2><p>We’ve grouped our macros into categories based the type of information being collected.</p><div class="info custom-block"><p class="custom-block-title">Using Functions to Modify Postback Macros</p><p>All postback macros can be hashed/encrypted/modified using a variety of postback URL functions. For information about the available postback URL functions applicable to the following postback macros, see the URL Function Macros section below.</p></div><h3 id="postback-data" tabindex="-1">Postback Data <a class="header-anchor" href="#postback-data" aria-label="Permalink to &quot;Postback Data&quot;">​</a></h3><p>The following macros represent the high-level data points associated with the postback event itself.</p><table tabindex="0"><thead><tr><th>Macro</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>${(name)!}</code></td><td>String</td><td>The name of the postback event. The list of event names can be found here.</td></tr><tr><td><code>${(customer_event_alias)!}</code></td><td>String</td><td>The alias name of the event provided by the customer; used in addition to the standard Branch names defined in the namefield.</td></tr><tr><td><code>${(organization_id)!}</code></td><td>Fixed64</td><td>The ID associated with your organization for which the event occurred; assigned by Branch.</td></tr><tr><td><code>${(organization_name)!}</code></td><td>String</td><td>The name of your organization for which the event occurred; provided during account setup.</td></tr><tr><td><code>${(event_timestamp)!}</code></td><td>Fixed64</td><td>The UNIX timestamp in milliseconds for the event; set automatically server side.</td></tr><tr><td><code>${(origin)!}</code></td><td>String</td><td>Where the attribution was recorded: - branch - segment - mparticle</td></tr><tr><td><code>${(id)!}</code></td><td>String</td><td>The ID associated with the event; assigned by Branch.</td></tr><tr><td><code>&lt;#if attributed&gt;1&lt;#else&gt;0&lt;/#if&gt;</code></td><td>Boolean</td><td>Whether or not the event is attributed; 1 (true/yes) OR 0 (false/no)</td></tr><tr><td><code>${(days_from_last_attributed_touch_to_event)!}</code></td><td>Int32</td><td>The number of days between the last attributed touch and the event.</td></tr><tr><td><code>${(hours_from_last_attributed_touch_to_event)!}</code></td><td>Int32</td><td>The number of hours between the last attributed touch and the event; capped at 24.</td></tr><tr><td><code>${(minutes_from_last_attributed_touch_to_event)!}</code></td><td>Int32</td><td>The number of minutes between the last attributed touch and the event; capped at 60.</td></tr><tr><td><code>${(seconds_from_last_attributed_touch_to_event)!}</code></td><td>Int32</td><td>The number of seconds between the last attributed touch and event; capped at 60.</td></tr><tr><td><code>${(last_attributed_touch_type)!}</code></td><td>String</td><td>The type of the attribution the event was for: - click - impression - impression</td></tr><tr><td><code>${(last_attributed_touch_timestamp)!}</code></td><td>Fixed64</td><td>The UNIX timestamp in milliseconds for the last attributed touch; set automatically server side.</td></tr><tr><td><code>${(di_match_click_token)!}</code></td><td>Fixed64</td><td>The Branch Flow ID used by other third party attribution providers to match a click to an install, using the Android install referrer; set server side, relayed by the client.</td></tr><tr><td><code>${last_cta_view_timestamp)!}</code></td><td>Fixed64</td><td>The UNIX timestamp in milliseconds for the last Branch CTA view. set automatically server side.</td></tr><tr><td><code>&lt;#if deep_linked&gt;1&lt;#else&gt;0&lt;/#if&gt;</code></td><td>Boolean</td><td>If the current app or web session resulted in the user being deep linked. set automatically server side; 1 (true/yes) OR 0 (false/no).</td></tr><tr><td><code>&lt;#if first_event_for_user&gt;1&lt;#else&gt;0&lt;/#if&gt;</code></td><td>Boolean</td><td>If this is the first time for this persona that this event has been triggered. set automatically server side; 1 (true/yes) OR 0 (false/no).</td></tr><tr><td><code>${(store_install_begin_timestamp)!}</code></td><td>Fixed64</td><td>The time the install button is clicked in the Play Store / App Store.</td></tr><tr><td><code>${(referrer_click_timestamp)!}</code></td><td>Fixed64</td><td>The time of the Play Store launch (Android only)</td></tr><tr><td><code>&lt;#if existing_user&gt;1&lt;#else&gt;0&lt;/#if&gt;</code></td><td>Boolean</td><td>If the user associated with the event is pre-existing or new; 1 (true/yes) OR 0 (false/no)</td></tr><tr><td><code>${(webhook_id)!}</code></td><td>Fixed64</td><td>The ID of the webhook/postback itself; assigned by Branch.</td></tr><tr><td><code>${(webhook_partner_key)!}</code></td><td>String</td><td>The machine readable partner name to which Branch is sending payload; set automatically server side.</td></tr></tbody></table><h3 id="attributed-touch-data" tabindex="-1">Attributed Touch Data <a class="header-anchor" href="#attributed-touch-data" aria-label="Permalink to &quot;Attributed Touch Data&quot;">​</a></h3><p>The following macros represent the data points associated with aspects of the advertising campaign itself.</p><table tabindex="0"><thead><tr><th>Macro</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>${(last_attributed_touch_data.~id)!}</code></td><td>Fixed64</td><td>The ID for the last attributed touch (Short Links only). set automatically server side.</td></tr><tr><td><code>${(last_attributed_touch_data.~campaign)!}</code></td><td>String</td><td>The campaign (name) specified for the last attributed touch. can be specified on links by the client, or pre-filled automatically server side in some cases.</td></tr><tr><td><code>${(last_attributed_touch_data.~campaign_id)!}</code></td><td>String</td><td>The campaign ID specified for the last attributed touch. set automatically server side.</td></tr><tr><td><code>${(last_attributed_touch_data.~campaign_type)!}</code></td><td>String</td><td>The type of Google campaign; Google AAP field. set automatically server side.</td></tr><tr><td><code>${(last_attributed_touch_data.~customer_campaign)!}</code></td><td>String</td><td>The customer campaign specified for the last attributed touch. can be specified on links by the client.</td></tr><tr><td><code>${(last_attributed_touch_data.~channel)!}</code></td><td>String</td><td>The channel specified for the last attributed touch. can be specified on links by the client, or pre-filled automatically server side in some cases.</td></tr><tr><td><code>${(last_attributed_touch_data.~feature)!}</code></td><td>String</td><td>The feature specified for the last attributed touch. can be specified on links by the client, or pre-filled automatically server side in some cases.</td></tr><tr><td><code>${(last_attributed_touch_data.~stage)!}</code></td><td>String</td><td>The stage specified for the last attributed touch. can be specified on links by the client, or pre-filled automatically server side in some cases.</td></tr><tr><td><code>${(last_attributed_touch_data.~tags)!}</code></td><td>String</td><td>The tags specified for the last attributed touch. can be specified on links by the client, or prefilled automatically server side in some cases.</td></tr><tr><td><code>${(last_attributed_touch_data.~advertising_partner_name)!}</code></td><td>String</td><td>The human-readable advertising partner name specified for the last attributed touch. set automatically server side.</td></tr><tr><td><code>${(last_attributed_touch_data.~advertising_partner_id)!}</code></td><td>String</td><td>The ID for the advertising partner specified for the last attributed touch. set automatically server side OR specified by the client.</td></tr><tr><td><code>${(last_attributed_touch_data.~secondary_publisher)!}</code></td><td>String</td><td>The secondary publisher specified for the last attributed touch. passed by the ad network.</td></tr><tr><td><code>${(last_attributed_touch_data.~secondary_publisher_id)!}</code></td><td>String</td><td>The ID of the secondary publisher specified for the last attributed touch. passed by the ad network.</td></tr><tr><td><code>${(last_attributed_touch_data.~customer_secondary_publisher)!}</code></td><td>String</td><td>The ID of the secondary publisher specified for the last attributed touch. passed by the ad network.</td></tr><tr><td><code>${(last_attributed_touch_data.~creative_name)!}</code></td><td>String</td><td>The creative name specified for the last attributed touch. set automatically server side.</td></tr><tr><td><code>${(last_attributed_touch_data.~creative_id)!}</code></td><td>String</td><td>The creative ID specified for the last attributed touch. set automatically server side.</td></tr><tr><td><code>${(last_attributed_touch_data.~ad_set_name)!}</code></td><td>String</td><td>The ad set name specified for the last attributed touch. set automatically server side.</td></tr><tr><td><code>${(last_attributed_touch_data.~ad_set_id)!}</code></td><td>String</td><td>The ad set ID specified for the last attributed touch. set automatically server side.</td></tr><tr><td><code>${(last_attributed_touch_data.~customer_ad_set_name)!}</code></td><td>String</td><td>The customer ad set name specified for the last attributed touch. can be specified on links by the client.</td></tr><tr><td><code>${(last_attributed_touch_data.~ad_name)!}</code></td><td>String</td><td>The ad name specified for the last attributed touch. set automatically server side.</td></tr><tr><td><code>${(last_attributed_touch_data.~ad_id)!}</code></td><td>String</td><td>The ad ID specified for the last attributed touch. set automatically server side.</td></tr><tr><td><code>${(last_attributed_touch_data.~customer_ad_name)!}</code></td><td>String</td><td>The customer ad name specified for the last attributed touch. can be specified on the link by the client.</td></tr><tr><td><code>${(last_attributed_touch_data.~keyword)!}</code></td><td>String</td><td>The keyword specified for the last attributed touch. set automatically server side.</td></tr><tr><td><code>${(last_attributed_touch_data.~keyword_id)!}</code></td><td>String</td><td>The unique ID for keyword of the last touch as provided by Google.</td></tr><tr><td><code>${(last_attributed_touch_data.~customer_keyword)!}</code></td><td>String</td><td>The customer keyword of the last touch. Can be specified on links by the client.</td></tr><tr><td><code>${(last_attributed_touch_data.~branch_ad_format)!}</code></td><td>String</td><td>The ad format of the last touch. Ad Format chosen upon Branch link creation and set as an analytics tag. e.g. Search, Display, Product Ad, App only.</td></tr><tr><td><code>${(last_attributed_touch_data.~technology_partner)!}</code></td><td>String</td><td>The technology partner of last touch, as set with an analytics tag. Any third party that&#39;s used to enhance a campaign (e.g. audiences being provided, creative optimization), with the exception of agencies.</td></tr><tr><td><code>${(last_attributed_touch_data.~banner_dimensions)!}</code></td><td>String</td><td>The dimensions of display banner of the last touch, as set with an analytics tag</td></tr><tr><td><code>${(last_attributed_touch_data.~placement)!}</code></td><td>String</td><td>The placement of the last touch, as set with an analytics tag. Actual app or website the ad appears on display campaigns.</td></tr><tr><td><code>${(last_attributed_touch_data.~placement_id)!}</code></td><td>String</td><td>The ID of placement of the last touch, as set with an analytics tag. Actual app or website the ad appears on display campaigns.</td></tr><tr><td><code>${(last_attributed_touch_data.~customer_placement)!}</code></td><td>String</td><td>The customer specified placement of the last touch, as set with an analytics tag. Actual app or website the ad appears on display campaigns.</td></tr><tr><td><code>${(last_attributed_touch_data.~sub_site_name)!}</code></td><td>String</td><td>Reference to the site where the ad was displayed. passed by the ad network.</td></tr><tr><td><code>${(last_attributed_touch_data.~customer_sub_site_name)!}</code></td><td>String</td><td>Customer reference to the site where the ad was displayed. Can be specified on links by the client.</td></tr><tr><td><code>${(last_attributed_touch_data.~agency)!}</code></td><td>String</td><td>The agency of the last touch, as set with an analytics tag. Agency that runs ad campaigns on behalf of advertiser.</td></tr><tr><td><code>${(last_attributed_touch_data.~agency_id)!}</code></td><td>String</td><td>The ID of agency of the last touch, as set with an analytics tag. Agency that runs ad campaigns on behalf of advertiser.</td></tr><tr><td><code>${(last_attributed_touch_data.~optimization_model)!}</code></td><td>String</td><td>Optimization model of the last touch, as set with an analytics tag. Model detailing the event for which the campaign is optimizing, e.g. for installs, clicks, events.</td></tr><tr><td><code>${(last_attributed_touch_data.~secondary_ad_format)!}</code></td><td>String</td><td>Secondary ad format of the last touch, as set with an analytics tag or during ad link creation flow in the dashboard. Ad Partner Specific Ad format, such as Display Engagement Ad for Google.</td></tr><tr><td><code>${(last_attributed_touch_data.~external_touch)!}</code></td><td>String</td><td>The ID of click or impression (view) sent to Branch from a third party. Used to tie an attributed event back to the original touch. Where the attributed partner is Google SAN, this will be the gclid value. See gclid in this sheet for more information.</td></tr><tr><td><code>${(last_attributed_touch_data.~journey_name)!}</code></td><td>String</td><td>The &quot;Campaign Name&quot; or &quot;title&quot; for an audience rule / Journey. can be specified on links by the client, or pre-filled automatically server side in some cases.</td></tr><tr><td><code>${(last_attributed_touch_data.~journey_id)!}</code></td><td>String</td><td>The audience rule ID for a Journey. set automatically server side.</td></tr><tr><td><code>${(last_attributed_touch_data.~view_name)!}</code></td><td>String</td><td>The &quot;View Name&quot; or &quot;title&quot; for a branch view / template. can be specified on links by the client, or pre-filled automatically server side in some cases.</td></tr><tr><td><code>${(last_attributed_touch_data.~view_id)!}</code></td><td>String</td><td>Branch view ID for a Journey. set automatically server side.</td></tr><tr><td><code>${(last_attributed_touch_data.+referring_domain)!}</code></td><td>String</td><td>Domain of the URL that the user visited before landing on a page with a Journey. This should use the same data source that we use for the &quot;came directly from a URL&quot; audience filter. specified by the client.</td></tr><tr><td><code>${(last_attributed_touch_data.dollar_3p)!}</code></td><td>String</td><td>Set if an event originated with a touch on Google AMP or Facebook Instant Article. specified by the client.</td></tr><tr><td><code>${(last_attributed_touch_data.+web_format)!}</code></td><td>String</td><td>The format of the webside: - amp - instant_articles</td></tr><tr><td><code>${(last_attributed_touch_data.+current_features)!}</code></td><td>String</td><td>Branch feature (determined by Branch) of the current touch. set automatically server side; - desktop_deepviews - desktop_journeys - mobile_deepviews - mobile_journeys - ads - email - social - quick_links</td></tr><tr><td><code>${(last_attributed_touch_data.+via_features)!}</code></td><td>String</td><td>All Branch features (determined by Branch) which were determined, via attribution, to have led to this event. For example, if an email link click leads to a Journey which leads to the app, the published eo_open will have +via_features: - EMAIL - JOURNEYS or set server side: - desktop_deepviews - desktop_journeys - mobile_deepviews - mobile_journeys - ads - email - social - quick_links</td></tr><tr><td><code>&lt;#if last_attributed_touch_data.dollar_fb_data_terms_not_signed&gt;1&lt;#else&gt;0&lt;/#if&gt;</code></td><td>Boolean</td><td>if the mobile data terms are not signed from facebook. this means we need to hide everything attribution-related from external events. set automatically server side; 1 (true/yes) OR 0 (false/no)</td></tr><tr><td><code>${(last_attributed_touch_data.+touch_id)!}</code></td><td>String</td><td>The attributing touch&#39;s (impression, click, etc) ID.</td></tr><tr><td><code>${(last_attributed_touch_data.custom_fields)!}</code></td><td>String</td><td>Any deep link data specified for the last touch not captured by the above fields e.g. {foo:true, deeplink_path: id/12}. &quot;custom_fields&quot; should not be surfaced as an independent object. The values should be included in last_attributed_touch_data. specified by the client.</td></tr><tr><td><code>${(last_attributed_touch_data.user_data_ip)!}</code></td><td>String</td><td>IP address of the user&#39;s device.</td></tr><tr><td><code>${(last_attributed_touch_data.user_data_user_agent)!}</code></td><td>String</td><td>The User-Agent string format including product name and version and system (e.g. “Mozilla/5.0 (iPad)”).</td></tr><tr><td><code>${(last_attributed_touch_data.+device_brand_name)!}</code></td><td>String</td><td>Brand or make of user&#39;s device (such as “Apple” or “Samsung”); determined by parsing the user-agent sent via HTTP headers.</td></tr><tr><td><code>${(last_attributed_touch_data.+device_brand_model)!}</code></td><td>String</td><td>Model of the user&#39;s device (such as “Droid Pro”); determined by parsing the user-agent sent via HTTP headers.</td></tr></tbody></table><h3 id="user-data" tabindex="-1">User Data <a class="header-anchor" href="#user-data" aria-label="Permalink to &quot;User Data&quot;">​</a></h3><p>The following macros represent the data points associated with the user / device collected at the time of conversion.</p><table tabindex="0"><thead><tr><th>Macro</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>${(user_data.os)!}</code></td><td>String</td><td>The operating system of the device on which the event was registered:</td></tr><tr><td><code>${(user_data.os_version)!}</code></td><td>String</td><td>The version of the operating system of the device on which the event was registered; specified by client.</td></tr><tr><td><code>${(user_data.os_version_android)!}</code></td><td>String</td><td>The operating system version (Android) of the device where the event occurred; specified by the client.</td></tr><tr><td><code>${(user_data.environment)!}</code></td><td>String</td><td>The runtime environment where the event occurred: - full_web - full_app - instant_app - imessage_app</td></tr><tr><td><code>${(user_data.platform)!}</code></td><td>String</td><td>A convenience dimension that allows users to easily see web vs app, desktop vs mobile, and iOS vs Android vs other</td></tr><tr><td><code>${(user_data.aaid)!}</code></td><td>String</td><td>Android/Google advertising id of the device where the event occurred. specified by the client.</td></tr><tr><td><code>${(user_data.android_id)!}</code></td><td>String</td><td>Android hardware id. Can only be reset by wiping the device. specified by the client.</td></tr><tr><td><code>${(user_data.idfa)!}</code></td><td>String</td><td>iOS advertising id of the device where the event occurred. specified by the client.</td></tr><tr><td><code>${(user_data.idfv)!}</code></td><td>String</td><td>OS vendor id of the device where the event occurred. Scoped to a vendor e.g. Facebook: idfv is the same for Facebook and Messenger but different Twitter. specified by the client.</td></tr><tr><td><code>${(user_data.kindle_aid)!}</code></td><td>String</td><td>The ID associated with a Kindle device.</td></tr><tr><td><code>${(user_data.windows_aid)!}</code></td><td>String</td><td>The Windows Advertising ID.</td></tr><tr><td><code>&lt;#if user_data.limit_ad_tracking&gt;1&lt;#else&gt;0&lt;/#if&gt;</code></td><td>Boolean</td><td>If the partner has opted to not be tracked by advertisers. on iOS 10+, accompanied by idfa of 0s; 1 (true/yes) OR 0 (false/no).</td></tr><tr><td><code>&lt;#if user_data.is_jailbroken&gt;1&lt;#else&gt;0&lt;/#if&gt;</code></td><td>Boolean</td><td>If true, then the phone that sent this event was jailbroken; 1 (true/yes) OR 0 (false/no).</td></tr><tr><td><code>${(user_data.user_agent)!}</code></td><td>String</td><td>The user agent of the browser or app where the event occurred. Usually associated with a webview.</td></tr><tr><td><code>${(user_data.ip)!}</code></td><td>String</td><td>The IP address from which the API call tracking the event originated; set automatically server side.</td></tr><tr><td><code>${(user_data.developer_identity)!}</code></td><td>String</td><td>The developer-specified identity for a user; specified by the client.</td></tr><tr><td><code>${(user_data.language)!}</code></td><td>String</td><td>The <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank" rel="noreferrer">ISO 639-1 Code</a> of the language.</td></tr><tr><td><code>${(user_data.sdk_version)!}</code></td><td>String</td><td>The Branch SDK version used to track this event; specified by the client.</td></tr><tr><td><code>${(user_data.http_referrer)!}</code></td><td>String</td><td>The referral URL that led to the current page where Web SDK logged web session start; specified by the client.</td></tr><tr><td><code>${(user_data.referral_source)!}</code></td><td>String</td><td>Android: <code>activity.getCallingPackage()</code>. iOS: Web referrer, safari referrer, or bundle_id.</td></tr><tr><td><code>${(user_data.app_version)!}</code></td><td>String</td><td>The app version where the event occurred; specified by the client.</td></tr><tr><td><code>${(user_data.device_type)!}</code></td><td>String</td><td>The type of device</td></tr><tr><td><code>${(user_data.carrier_name)!}</code></td><td>String</td><td>Which carrier covers the device where the event occurred. specified by the client.</td></tr><tr><td><code>${(user_data.brand)!}</code></td><td>String</td><td>Brand or make of user device (such as “Apple” or “Samsung”).</td></tr><tr><td><code>${(user_data.model)!}</code></td><td>String</td><td>The model of the device where the event occurred. specified by the client.</td></tr><tr><td><code>${(user_data.geo_continent_code)!}</code></td><td>String</td><td>The continent code, derived from IP address (above), set automatically server side.</td></tr><tr><td><code>${(user_data.geo_region_code)!}</code></td><td>String</td><td>The region code, derived from IP address (above), set automatically server side.</td></tr><tr><td><code>${(user_data.geo_region_en)!}</code></td><td>String</td><td>The human-readable region, derived from IP address (above), set automatically server side.</td></tr><tr><td><code>${(user_data.geo_dma_code)!}</code></td><td>UInt32</td><td>The <a href="https://support.google.com/richmedia/answer/2745487?hl=en" target="_blank" rel="noreferrer">DMA Code</a>, derived from IP address (above), set automatically server side.</td></tr><tr><td><code>${(user_data.geo_city_code)!}</code></td><td>UInt32</td><td>The city code, derived from IP address (above), set automatically server side.</td></tr><tr><td><code>${(user_data.geo_city_en)!}</code></td><td>String</td><td>The human-readable city, derived from IP address (above), set automatically server side.</td></tr><tr><td><code>${(user_data.geo_lat)!}</code></td><td>Float</td><td>Latitude, derived from IP address (above), set automatically server side.</td></tr><tr><td><code>${(user_data.geo_lon)!}</code></td><td>Float</td><td>Longitude, derived from IP address (above), set automatically server side.</td></tr><tr><td><code>${(user_data.geo_country_code)!}</code></td><td>String</td><td>The <a href="https://en.wikipedia.org/wiki/List_of_ISO_3166_country_codes" target="_blank" rel="noreferrer">ISO 3166 code</a> of the country.</td></tr><tr><td><code>${(user_data.geo_country_en)!}</code></td><td>String</td><td>The country name in English, derived from IP address (above), set automatically server side.</td></tr><tr><td><code>${(user_data.geo_postal_code)!}</code></td><td>String</td><td>The postal code, derived from IP address (above), set automatically server side.</td></tr><tr><td><code>${(user_data.browser)!}</code></td><td>String</td><td>A human-readable name for the browser from which the web event originated. Derived from user-agent string. specified by the client.</td></tr><tr><td><code>${(user_data.installer_package_name)!}</code></td><td>String</td><td>The package name of the app that installed the app; set automatically server side.</td></tr><tr><td><code>${(user_data.cpu_type)!}</code></td><td>String</td><td>The type of central processing unit used by the device ; set automatically server side.</td></tr><tr><td><code>${(user_data.build)!}</code></td><td>String</td><td>The build version of the device ; set automatically server side.</td></tr><tr><td><code>${(user_data.internet_connection_type)!}</code></td><td>String</td><td>The type of connection to the internet (e.g. Wifi) used by the device ; set automatically server side.</td></tr><tr><td><code>${(user_data.screen_width)!}</code></td><td>String</td><td>The width of the screen of the device ; set automatically server side.</td></tr><tr><td><code>${(user_data.screen_height)!}</code></td><td>String</td><td>The height of the screen of the device; set automatically server side.</td></tr><tr><td><code>${(user_data.carrier_name)!}</code></td><td>String</td><td>The name of the carrier (e.g. Verizon) of the device ; set automatically server side.</td></tr></tbody></table><h3 id="event-data" tabindex="-1">Event Data <a class="header-anchor" href="#event-data" aria-label="Permalink to &quot;Event Data&quot;">​</a></h3><p>The following macros represent the data points associated with the events completed by the user / device collected at the time of conversion.</p><table tabindex="0"><thead><tr><th>Macro</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>${(event_data.transaction_id)!}</code></td><td>String</td><td>The partner-specified transaction id for their internal use. specified by the client.</td></tr><tr><td><code>${(event_data.currency)!}</code></td><td>String</td><td><a href="https://en.wikipedia.org/wiki/ISO_4217" target="_blank" rel="noreferrer">ISO 4217 Code</a> for currency.</td></tr><tr><td><code>${(event_data.revenue)!}</code></td><td>Double</td><td>The partner-specified revenue for the event. specified by the client.</td></tr><tr><td><code>${(event_data.revenue_in_usd)!}</code></td><td>Double</td><td>Revenue in USD, based off of revenue, currency, and exchange rate. set automatically server side.</td></tr><tr><td><code>${(event_data.exchange_rate)!}</code></td><td>Double</td><td>The exchange rate from the time the event occurred (may be up to 24 hours old but is typically updated within the hour). specified by the client.</td></tr><tr><td><code>${(event_data.shipping)!}</code></td><td>Double</td><td>Shipping cost associated with the transaction. specified by the client.</td></tr><tr><td><code>${(event_data.tax)!}</code></td><td>Double</td><td>Total tax associated with the transaction. specified by the client.</td></tr><tr><td><code>${(event_data.coupon)!}</code></td><td>String</td><td>Transaction coupon redeemed with the transaction (e.g. &quot;SPRING2017&quot;). specified by the client.</td></tr><tr><td><code>${(event_data.affiliation)!}</code></td><td>String</td><td>Store or affiliation from which this transaction occurred (e.g. Google Store). specified by the client.</td></tr><tr><td><code>${(event_data.search_query)!}</code></td><td>String</td><td>Search query associated with the event. specified by the client.</td></tr><tr><td><code>${(event_data.ad_type)!}</code></td><td>String</td><td>Ad type that the user saw or clicked on. Defined by Facebook. specified by the client: - banner - interstitial - rewarded_video - native</td></tr><tr><td><code>${(event_data.description)!}</code></td><td>String</td><td>Description associated with the event, not necessarily specific to any individual content items. specified by the client.</td></tr></tbody></table><h3 id="content-items-data" tabindex="-1">Content Items Data <a class="header-anchor" href="#content-items-data" aria-label="Permalink to &quot;Content Items Data&quot;">​</a></h3><p>The following macros represent the data points associated with the contents within events completed by the user / device collected at the time of conversion</p><table tabindex="0"><thead><tr><th>Macro</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>${(content_items[0].$content_schema)!}</code></td><td>String</td><td>The category / schema for a piece of content. specified by the client:commerce_auction / commerce_business / commerce_other / commerce_product / commerce_restaurant / commerce_service / commerce_travel_flight / commerce_travel_hotel / commerce_travel_other / game_state / media_image / media_mixed / media_music / media_other / media_video / other / text_article / text_blog / text_other / text_recipe / text_review / text_search_results / text_story / text_technical_doc</td></tr><tr><td><code>&lt;#if content_items[0].$publicly_indexable&gt;1&lt;#else&gt;0&lt;/#if&gt;</code></td><td>Boolean</td><td>true: content can be indexed for local (device) use OR false: cannot index for local use; specified by the client; 1 (true/yes) OR 0 (false/no)</td></tr><tr><td><code>&lt;#if content_items[0].$locally_indexable&gt;1&lt;#else&gt;0&lt;/#if&gt;</code></td><td>Boolean</td><td>true: content can be seen by anyone OR false: cannot index for public use; specified by the client; 1 (true/yes) OR 0 (false/no)</td></tr><tr><td><code>${(content_items[0].$exp_date!}</code></td><td>Fixed64</td><td>The last time afterwhich this content is no longer valid. null / 0 mean no limit. specified by the client.</td></tr><tr><td><code>${(content_items[0].$canonical_identifier)!}</code></td><td>String</td><td>Used to allow Branch to unify content/messages. specified by the client.</td></tr><tr><td><code>${(content_items[0].$og_title)!}</code></td><td>String</td><td>The rendered document title (also for searching) - if a collection then the title for the collection not the individual items. specified by the client.</td></tr><tr><td><code>${(content_items[0].$canonical_url)!}</code></td><td>String</td><td>A web URL which refers to the content on the public web (mobile or desktop). Preferably is a permalink, and used as canonical URL elsewhere (main website, AMP pages, etc.). specified by the client.</td></tr><tr><td><code>${(content_items[0].$og_description)!}</code></td><td>String</td><td>The description (for individual item). specified by the client.</td></tr><tr><td><code>${(content_items[0].$og_image_url)!}</code></td><td>String</td><td>The image URL. specified by the client.</td></tr><tr><td><code>${(content_items[0].$keywords)!}</code></td><td>String</td><td>Any keywords. specified by the client.</td></tr><tr><td><code>${(content_items[0].$price)!}</code></td><td>Double</td><td>The unit price for the product/content. specified by the client.</td></tr><tr><td><code>${(content_items[0].$price_in_usd)!}</code></td><td>Double</td><td>The unit price in USD, based off of price, currency, and exchange rate. specified by the client OR set automatically server side.</td></tr><tr><td><code>${(content_items[0].$quantity)!}</code></td><td>Double</td><td>The quantity of the item to be ordered (for PURCHASE, ADD_TO_CART, etc). specified by the client.</td></tr><tr><td><code>${(content_items[0].$value)!}</code></td><td>Double</td><td>The value is the product of <code>$price</code> multiplied by <code>$quantity</code>. specified by the client OR set automatically server side.</td></tr><tr><td><code>${(content_items[0].$value_in_usd)!}</code></td><td>Double</td><td>The value in USD (see <code>$value</code> above), based off of price, currency, and exchange rate. specified by the client OR set automatically server side.</td></tr><tr><td><code>${(content_items[0].$sku)!}</code></td><td>String</td><td>The product sku or product id. specified by the client.</td></tr><tr><td><code>${(content_items[0].$product_name)!}</code></td><td>String</td><td>The product&#39;s name. specified by the client.</td></tr><tr><td><code>${(content_items[0].$product_brand)!}</code></td><td>String</td><td>The product&#39;s brand. specified by the client.</td></tr><tr><td><code>${(content_items[0].$product_variant)!}</code></td><td>String</td><td>The product variant (e.g. XL). specified by the client; animals_and_pets_supplies / apparel_and_accessories / arts_and_entertainment / baby_and_toddler / business_and_industrial / cameras_and_optics / electronics / food_beverage_and_tobacco / furniture / hardware / health_and_beauty / home_and_garden / luggage_and_bags / mature / media / office_supplies / religious_and_ceremonial / software / sporting_goods / toys_and_games / vehicles_and_parts</td></tr><tr><td><code>${(content_items[0].$rating)!}</code></td><td>Double</td><td>The rating given by the user on a <strong>RATE</strong> event. specified by the client.</td></tr><tr><td><code>${(content_items[0].$rating_average)!}</code></td><td>Double</td><td>The average rating of the item. specified by the client.</td></tr><tr><td><code>${(content_items[0].$rating_count)!}</code></td><td>Int64</td><td>The number of ratings for the item. specified by the client.</td></tr><tr><td><code>${(content_items[0].$rating_max)!}</code></td><td>Double</td><td>The maximum possible rating for the item (e.g. 5 stars is highest possible rating). specified by the client.</td></tr><tr><td><code>${(content_items[0].$address_street)!}</code></td><td>String</td><td>The street address for a restaurant, business, room (hotel), etc. specified by the client.</td></tr><tr><td><code>${(content_items[0].$address_city)!}</code></td><td>String</td><td>The city for a restaurant, business, room (hotel), etc. specified by the client.</td></tr><tr><td><code>${(content_items[0].$address_country)!}</code></td><td>String</td><td>The country code for a restaurant, business, room (hotel), etc. specified by the client.</td></tr><tr><td><code>${(content_items[0].$address_postal_code)!}</code></td><td>String</td><td>The postal/zip code for a restaurant, business, room (hotel), etc. specified by the client.</td></tr><tr><td><code>${(content_items[0].$latitude)!}</code></td><td>Float</td><td>The latitude for a restaurant, business, room (hotel), etc. specified by the client.</td></tr><tr><td><code>${(content_items[0].$longitude)!}</code></td><td>Float</td><td>The longitude for a restaurant, business, room (hotel), etc. specified by the client.</td></tr><tr><td><code>${(content_items[0].$condition)!}</code></td><td>String</td><td>For auctions, whether the item is new, good, acceptable, etc. specified by the client; new / excellent / good / fair / poor / used / refurbished / other</td></tr><tr><td><code>${(content_items[0].$image_captions)!}</code></td><td>String</td><td>The captions associated with the image. specified by the client.</td></tr><tr><td><code>${(content_items[0].$creation_timestamp)!}</code></td><td>Fixed64</td><td>The time the content was created. specified by the client.</td></tr><tr><td><code>${(content_items[0].$currency)!}</code></td><td>String</td><td>The <a href="https://en.wikipedia.org/wiki/ISO_4217" target="_blank" rel="noreferrer">ISO 4217 code</a> of currency.</td></tr><tr><td><code>${(content_items[0].custom_fields)!}</code></td><td>String</td><td>The partner-specified custom key-value pairs associated with a BUO. specified by the client.</td></tr></tbody></table><h3 id="cohort-related-data" tabindex="-1">Cohort Related Data <a class="header-anchor" href="#cohort-related-data" aria-label="Permalink to &quot;Cohort Related Data&quot;">​</a></h3><p>The following macros represent the data points associated with the cohorted users based on install or re-engagement activity.</p><table tabindex="0"><thead><tr><th>Macro</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>${(install_activity.event_name)!}</code> <strong>OR</strong> <code>${(reengagement_activity.event_name)!}</code></td><td>String</td><td>The name of the cohort event.</td></tr><tr><td><code>&lt;#if install_activity.attributed&gt;1&lt;#else&gt;0&lt;/#if&gt;</code><strong>OR</strong><code>&lt;#if reengagement_activity.attributed&gt;1&lt;#else&gt;0&lt;/#if&gt;</code></td><td>Boolean</td><td>Whether or not the install/reengagement event is attributed; 1 (true/yes) OR 0 (false/no)</td></tr><tr><td><code>${(install_activity.timestamp)!}</code> <strong>OR</strong> <code>${(reengagement_activity.timestamp)!}</code></td><td>Fixed64</td><td>An epoch timestamp for the time of the install/reengagement in UTC in milliseconds</td></tr><tr><td><code>${(install_activity.touch_data.tilde_advertising_partner_name)!}</code> <strong>OR</strong> <code>${(reengagement_activity.touch_data.tilde_advertising_partner_name)!}</code></td><td>String</td><td>The human-readable advertising partner name specified for the last attributed touch. set automatically server side.</td></tr><tr><td><code>${(install_activity.touch_data.dollar_3p)!}</code> <strong>OR</strong> <code>${(reengagement_activity.touch_data.dollar_3p)!}</code></td><td>String</td><td>Set if an event originated with a touch on Google AMP or Facebook Instant Article. specified by the client.</td></tr></tbody></table><h3 id="cta-view-data" tabindex="-1">CTA View Data <a class="header-anchor" href="#cta-view-data" aria-label="Permalink to &quot;CTA View Data&quot;">​</a></h3><p>The following macros represent the data points associated with Journeys or Deepview data where there is no link click.</p><table tabindex="0"><thead><tr><th>Macro</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>${(last_cta_view_data.~id)!}</code></td><td>Fixed64</td><td>The ID for the last CTA view. set automatically server side.</td></tr><tr><td><code>${(last_cta_view_data.~campaign)!}</code></td><td>String</td><td>The campaign (name) specified for the last CTA view. can be specified on links by the client, or prefilled automatically server side in some cases.</td></tr><tr><td><code>${(last_cta_view_data.~campaign_id)!}</code></td><td>String</td><td>The campaign ID specified for the last CTA view. set automatically server side.</td></tr><tr><td><code>${(last_cta_view_data.~campaign_type)!}</code></td><td>String</td><td>The type of Google campaign; Google AAP field. set automatically server side.</td></tr><tr><td><code>${(last_cta_view_data.~customer_campaign)!}</code></td><td>String</td><td>The customer campaign specified for the last CTA view. can be specified on links by the client.</td></tr><tr><td><code>${(last_cta_view_data.~channel)!}</code></td><td>String</td><td>The channel specified for the last CTA view. can be specified on links by the client, or prefilled automatically server side in some cases.</td></tr><tr><td><code>${(last_cta_view_data.~feature)!}</code></td><td>String</td><td>The feature specified for the last CTA view. can be specified on links by the client, or prefilled automatically server side in some cases.</td></tr><tr><td><code>${(last_cta_view_data.~stage)!}</code></td><td>String</td><td>The stage specified for the last CTA view. can be specified on links by the client, or prefilled automatically server side in some cases.</td></tr><tr><td><code>${(last_cta_view_data.~tags)!}</code></td><td>String</td><td>The tags specified for the last CTA view. can be specified on links by the client, or prefilled automatically server side in some cases.</td></tr><tr><td><code>${(last_cta_view_data.~advertising_partner_name)!}</code></td><td>String</td><td>The human-readable advertising partner name specified for the last CTA view. set automatically server side.</td></tr><tr><td><code>${(last_cta_view_data.~advertising_partner_id)!}</code></td><td>String</td><td>The ID for the advertising partner specified for the last CTA view. set automatically server side OR specified by the client.</td></tr><tr><td><code>${(last_cta_view_data.~secondary_publisher)!}</code></td><td>String</td><td>The secondary publisher specified for the last CTA view. passed by the ad network.</td></tr><tr><td><code>${(last_cta_view_data.~secondary_publisher_id)!}</code></td><td>String</td><td>The ID of the secondary publisher specified for the last CTA view. passed by the ad network.</td></tr><tr><td><code>${(last_cta_view_data.~customer_secondary_publisher)!}</code></td><td>String</td><td>The ID of the secondary publisher specified for the last CTA view. passed by the ad network.</td></tr><tr><td><code>${(last_cta_view_data.~creative_name)!}</code></td><td>String</td><td>The creative name specified for the last CTA view. set automatically server side.</td></tr><tr><td><code>${(last_cta_view_data.~creative_id)!}</code></td><td>String</td><td>The creative ID specified for the last CTA view. set automatically server side.</td></tr><tr><td><code>${(last_cta_view_data.~ad_set_name)!}</code></td><td>String</td><td>The ad set name specified for the last CTA view. set automatically server side.</td></tr><tr><td><code>${(last_cta_view_data.~ad_set_id)!}</code></td><td>String</td><td>The ad set ID specified for the last CTA view. set automatically server side.</td></tr><tr><td><code>${(last_cta_view_data.~customer_ad_set_name)!}</code></td><td>String</td><td>The customer ad set name specified for the last CTA view. can be specified on links by the client.</td></tr><tr><td><code>${(last_cta_view_data.~ad_name)!}</code></td><td>String</td><td>The ad name specified for the last CTA view. set automatically server side.</td></tr><tr><td><code>${(last_cta_view_data.~ad_id)!}</code></td><td>String</td><td>The ad ID specified for the last CTA view. set automatically server side.</td></tr><tr><td><code>${(last_cta_view_data.~customer_ad_name)!}</code></td><td>String</td><td>The customer ad name specified for the last CTA view. can be specified on the link by the client.</td></tr><tr><td><code>${(last_cta_view_data.~keyword)!}</code></td><td>String</td><td>The keyword specified for the last CTA view. set automatically server side.</td></tr><tr><td><code>${(last_cta_view_data.~keyword_id)!}</code></td><td>String</td><td>The unique ID for keyword of the last view as provided by Google.</td></tr><tr><td><code>${(last_cta_view_data.~customer_keyword)!}</code></td><td>String</td><td>The customer keyword of the last view. Can be specified on links by the client.</td></tr><tr><td><code>${(last_cta_view_data.~branch_ad_format)!}</code></td><td>String</td><td>The ad format of the last view. Ad Format chosen upon Branch link creation and set as an analytics tag. e.g. Search, Display, Product Ad, App only.</td></tr><tr><td><code>${(last_cta_view_data.~technology_partner)!}</code></td><td>String</td><td>The technology partner of last view, as set with an analytics tag. Any third party that&#39;s used to enhance a campaign (e.g. audiences being provided, creative optimization), with the exception of agencies</td></tr><tr><td><code>${(last_cta_view_data.~banner_dimensions!}</code></td><td>String</td><td>The dimensions of display banner of the last view, as set with an analytics tag.</td></tr><tr><td><code>${(last_cta_view_data.~placement)!}</code></td><td>String</td><td>The placement of the last view, as set with an analytics tag. Actual app or website the ad appears on display campaigns</td></tr><tr><td><code>${(last_cta_view_data.~placement_id)!}</code></td><td>String</td><td>The ID of placement of the last view, as set with an analytics tag. Actual app or website the ad appears on display campaigns</td></tr><tr><td><code>${(last_cta_view_data.~customer_placement)!}</code></td><td>String</td><td>The customer specified placement of the last view, as set with an analytics tag. Actual app or website the ad appears on display campaigns</td></tr><tr><td><code>${(last_cta_view_data.~sub_site_name)!}</code></td><td>String</td><td>Reference to the site where the ad was displayed. passed by the ad network.</td></tr><tr><td><code>${(last_cta_view_data.~customer_sub_site_name)!}</code></td><td>String</td><td>Customer reference to the site where the ad was displayed. Can be specified on links by the client.</td></tr><tr><td><code>${(last_cta_view_data.~agency)!}</code></td><td>String</td><td>The agency of the last view, as set with an analytics tag. Agency that runs ad campaigns on behalf of advertiser.</td></tr><tr><td><code>${(last_cta_view_data.~agency_id)!}</code></td><td>String</td><td>The ID of agency of the last view, as set with an analytics tag. Agency that runs ad campaigns on behalf of advertiser.</td></tr><tr><td><code>${(last_cta_view_data.~optimization_model)!}</code></td><td>String</td><td>Optimization model of the last view, as set with an analytics tag. Model detailing the event for which the campaign is optimizing, e.g. for installs, clicks, events</td></tr><tr><td><code>${(last_cta_view_data.~secondary_ad_format)!}</code></td><td>String</td><td>Secondary ad format of the last view, as set with an analytics tag or during ad link creation flow in the dashboard. Ad Partner Specific Ad format, such as Display Engagement Ad for Google.</td></tr><tr><td><code>${(last_cta_view_data.~external_touch_id)!}</code></td><td>String</td><td>The ID of click or impression (view) sent to Branch from a third party. Used to tie an attributed event back to the original touch. Where the attributed partner is Google SAN, this will be the gclid value. See <code>gclid</code> in this sheet for more information.</td></tr><tr><td><code>${(last_cta_view_data.~journey_name)!}</code></td><td>String</td><td>The &quot;Campaign Name&quot; or &quot;title&quot; for an audience rule / Journey. can be specified on links by the client, or prefilled automatically server side in some cases.</td></tr><tr><td><code>${(last_cta_view_data.~journey_id)!}</code></td><td>String</td><td>The audience rule ID for a Journey. set automatically server side.</td></tr><tr><td><code>${(last_cta_view_data.~view_name)!}</code></td><td>String</td><td>The &quot;View Name&quot; or &quot;title&quot; for a branch view / template. can be specified on links by the client, or prefilled automatically server side in some cases.</td></tr><tr><td><code>${(last_cta_view_data.~view_id)!}</code></td><td>String</td><td>Branch view ID for a Journey. set automatically server side.</td></tr><tr><td><code>${(last_cta_view_data.plus_referring_domain)!}</code></td><td>String</td><td>Domain of the URL that the user visited before landing on a page with a Journey. This should use the same data source that we use for the &quot;came directly from a URL&quot; audience filter. specified by the client.</td></tr><tr><td><code>${(last_cta_view_data.3p)!}</code></td><td>String</td><td>Set if an event originated with a touch on Google AMP or Facebook Instant Article. specified by the client.</td></tr><tr><td><code>${(last_cta_view_data.+web_format)!}</code></td><td>String</td><td>The format of the website; - amp - instant_articles</td></tr><tr><td><code>${(last_cta_view_data.+via_features)!}</code></td><td>String</td><td>Branch feature (determined by Branch) of the current touch. set automatically server side; desktop_deepviews / desktop_journeys / mobile_deepviews / mobile_journeys / ads / email / social / quick_links</td></tr><tr><td><code>${(last_cta_view_data.+touch_id)!}</code></td><td>String</td><td>The attributing touch&#39;s (impression, click, etc) ID</td></tr><tr><td><code>${(last_cta_view_data.custom_fields)!}</code></td><td>String</td><td>Any deep link data specified for the last view not captured by the above fields e.g. {foo:true, deeplink_path: &#39;id/12&#39;}. &quot;custom_fields&quot; should not be surfaced as an independent object. The values should be included in last_attributed_touch_data. specified by the client.</td></tr></tbody></table><h3 id="custom-data" tabindex="-1">Custom Data <a class="header-anchor" href="#custom-data" aria-label="Permalink to &quot;Custom Data&quot;">​</a></h3><p>The following macros represent the data points associated with the custom data points pre-assigned by Branch.</p><table tabindex="0"><thead><tr><th>Macro</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>${(custom_data.sub1)!}</code></td><td>String</td><td>General-purpose field for passing data from click through to installs, opens, and conversion events.</td></tr><tr><td><code>${(custom_data.sub2)!}</code></td><td>String</td><td>General-purpose field for passing data from click through to installs, opens, and conversion events.</td></tr><tr><td><code>${(custom_data.sub3)!}</code></td><td>String</td><td>General-purpose field for passing data from click through to installs, opens, and conversion events.</td></tr><tr><td><code>${(custom_data.sub4)!}</code></td><td>String</td><td>General-purpose field for passing data from click through to installs, opens, and conversion events.</td></tr><tr><td><code>${(custom_data.sub5)!}</code></td><td>String</td><td>General-purpose field for passing data from click through to installs, opens, and conversion events.</td></tr><tr><td><code>${(custom_data.content_id)!}</code></td><td>String</td><td>ID of the content interacted with during an in-app event.</td></tr><tr><td><code>${(custom_data.content_type)!}</code></td><td>String</td><td>The type of content interacted with during an in-app event.</td></tr><tr><td><code>${(custom_data.date1)!}</code></td><td>String</td><td>Time of check-in for the in-app event “reservation”.</td></tr><tr><td><code>${(custom_data.date2)!}</code></td><td>String</td><td>Time of check-out for the in-app event “reservation”.</td></tr><tr><td><code>${(custom_data.level)!}</code></td><td>String</td><td>The event level achieved.</td></tr><tr><td><code>${(custom_data.quantity)!}</code></td><td>String</td><td>The count related to an in-app event; e.g. number of guests or credits spent.</td></tr><tr><td><code>${(custom_data.rating)!}</code></td><td>String</td><td>The rating related to an in-app event; e.g. a 4 star rating.</td></tr><tr><td><code>${(custom_data.transaction_id)!}</code></td><td>String</td><td>ID of the transaction recorded on conversion.</td></tr></tbody></table><h2 id="url-function-macros-freemarker" tabindex="-1">URL Function Macros &amp; Freemarker <a class="header-anchor" href="#url-function-macros-freemarker" aria-label="Permalink to &quot;URL Function Macros &amp; Freemarker&quot;">​</a></h2><p>Along with our URL macros, we also support a variety of URL functions to be used in conjunction with our macros. Using functions gives you more control over how your data is formatted for your own internal uses.</p><p>We’ve grouped our functions into categories based on what type of action is being taken as well as what type of information is being handled.</p><p>More information on Freemarker can be found <a href="https://freemarker.apache.org/docs/ref_directive_alphaidx.html" target="_blank" rel="noreferrer">here</a>.</p><h3 id="hashing-encoding-etc" tabindex="-1">Hashing/Encoding/etc. <a class="header-anchor" href="#hashing-encoding-etc" aria-label="Permalink to &quot;Hashing/Encoding/etc.&quot;">​</a></h3><p>Function macros that can hash, encode/decode or otherwise modify another macro’s value; e.g. the MD5 hash of a unique identifier.</p><table tabindex="0"><thead><tr><th>Hashing/Encoding/etc.</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>&lt;@alphanumeric&gt;INPUT_MACRO_HERE</code></td><td>Function</td><td>Removes non-alphanumeric characters from a string.</td></tr><tr><td><code>&lt;@base64&gt;INPUT_MACRO_HERE</code></td><td>Base64</td><td>Base64 encodes the contents</td></tr><tr><td><code>&lt;@json&gt;INPUT_MACRO_HERE</code></td><td>JSON</td><td>JSON encodes the contents as a string.</td></tr><tr><td><code>&lt;@jsonmap&gt;INPUT_MACRO_HERE</code></td><td>JSON</td><td>JSON encodes the data (be sure not to quote), in whatever.</td></tr><tr><td><code>&lt;@lower&gt;INPUT_MACRO_HERE</code></td><td>Function</td><td>Returns the inputted value formatted as lowercase with separating colons.</td></tr><tr><td><code>&lt;@md5&gt;INPUT_MACRO_HERE</code></td><td>MD5</td><td>MD5 encodes the contents</td></tr><tr><td><code>&lt;@sha1&gt;INPUT_MACRO_HERE</code></td><td>SHA1</td><td>SHA1 encodes the contents</td></tr><tr><td><code>&lt;@sha256&gt;INPUT_MACRO_HERE</code></td><td>SHA256</td><td>SHA256 encodes the contents</td></tr><tr><td><code>&lt;@upper&gt;INPUT_MACRO_HERE</code></td><td>Function</td><td>Returns the inputted value formatted as uppercase with separating colons.</td></tr><tr><td><code>&lt;@urldecode&gt;INPUT_MACRO_HERE</code></td><td>Decode</td><td>URL decodes the contents.</td></tr><tr><td><code>&lt;@urlencode&gt;INPUT_MACRO_HERE</code></td><td>Encode</td><td>URL encodes the contents.</td></tr></tbody></table><h3 id="datetime" tabindex="-1">Datetime <a class="header-anchor" href="#datetime" aria-label="Permalink to &quot;Datetime&quot;">​</a></h3><p>Function macros that return datetime information about another macro’s value; e.g. the time of an in-app purchase event.</p><table tabindex="0"><thead><tr><th>Format</th><th>Description</th></tr></thead><tbody><tr><td><code>&lt;@dateformat output_date_format=&quot;yyyy-MM-dd&quot;&gt;INPUT_MACRO_HERE</code></td><td>Returns the calendar date of the specified conversion</td></tr><tr><td><code>&lt;@dateformat output_date_format=&quot;yyyy-MM-dd HH:mm:ss&quot;&gt;INPUT_MACRO_HERE</code></td><td>Returns the DateTime of the specified conversion</td></tr><tr><td><code>&lt;@dateformat output_date_format=&quot;TIMESTAMP_SECONDS&quot;&gt;INPUT_MACRO_HERE</code></td><td>Returns the current unix timestamp in seconds of the specified conversion</td></tr><tr><td><code>&lt;@dateformat output_date_format=&quot;TIMESTAMP_MILLIS&quot;&gt;INPUT_MACRO_HERE</code></td><td>Returns the current unixt timestamp in milliseconds of the specified conversion</td></tr><tr><td><code>&lt;@iso8601UTCDate&gt;INPUT_MACRO_HERE</code></td><td>Format a <code>DateTime</code> value in <a href="https://en.wikipedia.org/wiki/ISO_8601" target="_blank" rel="noreferrer">ISO 8601 UTC</a>. Returns an empty string for missing data or data that is not a <code>DateTime</code>. As <code>DateTime</code> doesn’t store millisecond precision, milliseconds are hard-coded to 000</td></tr></tbody></table><h3 id="general-actions" tabindex="-1">General Actions <a class="header-anchor" href="#general-actions" aria-label="Permalink to &quot;General Actions&quot;">​</a></h3><p>Function macros that perform a variety of general use actions; e.g. modifying a boolean value into an integer.</p><table tabindex="0"><thead><tr><th>Action</th><th>Description</th></tr></thead><tbody><tr><td><code>&lt;@countryCodeIso3166&gt;INPUT_MACRO_HERE</code></td><td>Returns the <a href="https://en.wikipedia.org/wiki/ISO_3166-1" target="_blank" rel="noreferrer">ISO 3166-1</a> two-letter country code.</td></tr><tr><td><code>&lt;@firstNotEmpty&gt;INPUT_MACRO_HERE</code></td><td>Gets the first value that isn’t empty in a delimited string.</td></tr><tr><td><code>&lt;@languageIso639&gt;INPUT_MACRO_HERE</code></td><td>Returns the <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank" rel="noreferrer">ISO 639-1</a> two-character language code.</td></tr><tr><td><code>&lt;@loop data=app.app_bundles val=&quot;bundle&quot;&gt;&lt;#if user_data.os == bundle.os&gt;``&lt;/#if&gt;``&lt;#if bundle.os==&quot;ANDROID&quot;&gt;${(bundle.android.package_name)}&lt;@break/&gt; &lt;/#if&gt;&lt;/@loop&gt;</code></td><td>Return the <code>store_app_id</code> for an iOS site and a <code>package_name</code> for an Android site.</td></tr><tr><td><code>&lt;@loop&gt;INPUT_MACRO_HERE</code>, <code>&lt;@break&gt;</code>, <code>&lt;@sep&gt;</code></td><td>Loops around the variable specified in data, assigning each successive one to the name specified in val. Be sure not to put quotes around data.</td></tr><tr><td><code>&lt;@rand&gt;INPUT_MACRO_HERE</code></td><td>Returns a random value between 0 and 2^31.</td></tr><tr><td><code>&lt;@ternary&gt;INPUT_MACRO_HERE</code></td><td>A basic implementation of ternary functionality that uses</td></tr><tr><td><code>&lt;@truncate&gt;INPUT_MACRO_HERE</code></td><td>Returns a value shortened to 40 characters in length.</td></tr><tr><td><code>&lt;#assign captured&gt;%s</code></td><td>Casts a boolean string to its integer counter part.</td></tr><tr><td><code>&lt;#if user_data.os == &quot;IOS&quot;&gt;0&lt;#elseif user_data.os == &quot;ANDROID&quot;&gt;1&lt;#elseif user_data.os == &quot;WINDOWS&quot;&gt;2&lt;#else&gt;null&lt;/#if&gt;</code></td><td>Return the platform as an integer ios = 0, android = 1, windows = 2.</td></tr></tbody></table><h3 id="unsupported-freemarker-expressions" tabindex="-1">Unsupported Freemarker Expressions <a class="header-anchor" href="#unsupported-freemarker-expressions" aria-label="Permalink to &quot;Unsupported Freemarker Expressions&quot;">​</a></h3><p>Due to security restrictions, Branch does not support the below Freemarker expressions:</p><ul><li><code>&lt;#import&gt;</code></li><li><code>&lt;#visit&gt;</code></li><li><code>&lt;#include&gt;</code></li><li><code>?eval</code></li><li><code>&lt;#recurse&gt;</code></li><li><code>&lt;#setting&gt;</code></li><li><code>&lt;#macro&gt;</code></li><li><code>&lt;#function&gt;</code></li><li><code>&lt;#nested&gt;</code></li><li><code>&lt;#return&gt;</code></li><li><code>&lt;#list&gt;</code></li></ul>',45)])])}const p=e(o,[["render",i]]);export{_ as __pageData,p as default};
